import { notFound } from "next/navigation"
import { getSupabaseAdminClient } from "@/lib/supabase/server"
import CandidateApplicationForm from "@/components/candidate-application-form"
import type { FormData, WorkExperience, Education } from "@/components/candidate-application-form"

type PageProps = {
  params: Promise<{
    id: string
  }>
}

type WorkExperienceDB = {
  id: string
  company_name: string
  role: string
  start_month: string
  start_year: string
  end_month: string | null
  end_year: string | null
  description: string | null
  is_current: boolean
}

type EducationDB = {
  id: string
  degree: string
  institute: string
  start_year: string
  end_year: string
}

export default async function EditCandidatePage(props: PageProps) {
  const { id } = await props.params
  const supabase = getSupabaseAdminClient()

  // Fetch candidate data
  const { data: candidate, error: candidateError } = await supabase
    .from("candidates")
    .select("*")
    .eq("id", id)
    .single()

  if (candidateError || !candidate) {
    console.error("[Edit Page] Failed to load candidate:", candidateError)
    notFound()
  }

  // Fetch work experiences
  const { data: experiences } = await supabase
    .from("work_experiences")
    .select("*")
    .eq("candidate_id", id)
    .order("display_order", { ascending: true })
    .order("start_year", { ascending: false })

  // Fetch educations
  const { data: educations } = await supabase
    .from("educations")
    .select("*")
    .eq("candidate_id", id)
    .order("display_order", { ascending: true })
    .order("start_year", { ascending: false })

  // Transform database format to form format
  const transformWorkExperiences = (exps: WorkExperienceDB[] | null): WorkExperience[] => {
    if (!exps || exps.length === 0) return []
    return exps.map((exp) => ({
      companyName: exp.company_name || "",
      role: exp.role || "",
      startMonth: exp.start_month || "",
      startYear: exp.start_year || "",
      endMonth: exp.end_month || "",
      endYear: exp.end_year || "",
      description: exp.description || "",
      isCurrent: exp.is_current || false,
    }))
  }

  const transformEducations = (edus: EducationDB[] | null): Education[] => {
    if (!edus || edus.length === 0) return []
    return edus.map((edu) => ({
      degree: edu.degree || "",
      institute: edu.institute || "",
      startYear: edu.start_year || "",
      endYear: edu.end_year || "",
    }))
  }

  // Prepare initial form data
  const initialData: Partial<FormData> = {
    name: candidate.name || "",
    mobileNumber: candidate.mobile_number || "",
    email: candidate.email || "",
    currentLocation: candidate.current_location || "",
    currentSalaryCurrency: candidate.current_salary_currency || "",
    salaryRange: candidate.salary_range || "",
    nationality: candidate.nationality || "",
    gender: candidate.gender || "",
    seniorityLevel: candidate.seniority_level || "",
    reportingManager: candidate.reporting_manager || "",
    preferredLocation: candidate.preferred_location || "",
    skills: candidate.skills || "",
    experience: candidate.experience || "",
    expectedSalaryCurrency: candidate.expected_salary_currency || "",
    expectedSalaryRange: candidate.expected_salary_range || "",
    linkedinProfile: candidate.linkedin_profile || "",
    portfolio: candidate.portfolio || "",
    preferredRole: candidate.preferred_role || "",
    workPermitStatus: candidate.work_permit_status || "Nationality basis",
    employmentType: candidate.employment_type || "Permanent",
    workMode: candidate.work_mode || "Hybrid",
    references: candidate.references || "",
    noticePeriod: candidate.notice_period || "",
    activelySeekingToggle: candidate.actively_seeking_toggle || "Passive",
    workExperiences: transformWorkExperiences(experiences as WorkExperienceDB[] | null),
    educations: transformEducations(educations as EducationDB[] | null),
    // Note: cv and photograph are File | null, but we can't pre-fill files
    // They'll remain null and user can upload new ones if needed
    cv: null,
    photograph: null,
  }

  return (
    <div className="min-h-screen bg-background py-12 px-4">
      <div className="mx-auto max-w-4xl">
        <CandidateApplicationForm
          initialData={initialData}
          candidateId={id}
          isEditMode={true}
        />
      </div>
    </div>
  )
}
